// ──────────────────────────────────────────────────────────────────────────

trait ObjectRopeExt {
    fn set_rope(&mut self, rope: &Rope, bump: &Bump, value: Expr) -> Result<(), SetError>;
    fn get_or_put_array(&mut self, rope: &Rope, bump: &Bump) -> Result<Expr, SetError>;
}

